function createSettledPromise(): {
  promise: Promise<void>
  resolveOnce: () => void
  rejectOnce: (err: unknown) => void
} {
  let settled = false
  let resolve: () => void
  let reject: (err: unknown) => void
  const promise = new Promise<void>((res, rej) => {
    resolve = res
    reject = rej
  })
  return {
    promise,
    resolveOnce: () => { if (!settled) { settled = true; resolve() } },
    rejectOnce: (err: unknown) => { if (!settled) { settled = true; reject(err) } },
  }
}
// Usage in both functions:
const { promise, resolveOnce, rejectOnce } = createSettledPromise()

WHY: Eliminates exact duplication of promise-settling logic. The helper is a pure utility with clear semantics, making both stream functions shorter and the settle-once guarantee centrally testable.

