function createAiSdkChunkHandler(options: StreamOptions | undefined, rejectOnce: (err: unknown) => void) {
  return async ({ chunk }: { chunk: any }) => {
    try {
      if (chunk.type === 'text-delta')
        return options?.onStreamEvent?.({ type: 'text-delta', text: chunk.text })
      if (chunk.type === 'tool-call')
        return options?.onStreamEvent?.({ type: 'tool-call', toolName: chunk.toolName, toolCallId: chunk.toolCallId, args: JSON.stringify(chunk.input), toolCallType: 'function' } as StreamEvent)
      if (chunk.type === 'tool-result')
        return options?.onStreamEvent?.({ type: 'tool-result', toolCallId: chunk.toolCallId, result: chunk.output as string })
    } catch (err) { rejectOnce(err) }
  }
}
